INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility, participant_structure,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility', d.participant,
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Snap-Down to Low Vertical Rebound', 'snap-down-to-low-vertical-rebound', 'Perform Snap-Down to Low Vertical Rebound as a low-volume, high-quality plyometric or reactive-output exposure. The exercise targets low-amplitude rebound timing after a clean braking position. The coach should cap volume, demand clean landings, and stop the set before contact quality fades.', 'INTERMEDIATE', 8, 3, 5, NULL, 75, 35, 'individual', 'Snap-Down to Low Vertical Rebound is a level-3 high-impact Output drill for low-amplitude rebound timing after a clean braking position.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Coach this as level-3 high-impact Output work: small dose, long enough rest, clean projection, quiet landings, and an immediate stop when posture, timing, alignment, or reaction quality changes.', 'Fast and clean. Leave the ground with intent, land quietly, own the finish, and reset before the next rep.', 'High-Impact Level 3-4 Plyometric / Reactive Output', 'output', 'elastic_stiffness_plyometric_rudiments', 'snap_down_low_vertical_rebound', '{"primary_joint_actions":["ankle plantarflexion and dorsiflexion","knee flexion-extension control","hip flexion-extension","trunk bracing"],"primary_tissues":["calf complex","Achilles tendon","quadriceps","patellar tendon","glutes","hip flexors","abdominals","obliques"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_exhale_or_relaxed_reset","balance_demand":"dynamic","coordination_demand":"high","impact_level":3,"surface_needs":"flat, non-slip, shock-absorbing surface with safe spacing","readiness_prerequisites":["Pain-free jumping, hopping, landing, and deceleration patterns.","Can demonstrate a lower-level landing or rebound progression quietly and under control.","Understands stop command and can reset between reps."]}'::jsonb, '{"movement_description":"Perform Snap-Down to Low Vertical Rebound as a low-volume, high-quality plyometric or reactive-output exposure. The exercise targets low-amplitude rebound timing after a clean braking position. The coach should cap volume, demand clean landings, and stop the set before contact quality fades.","setup":["Choose a safe lane, surface, target, cone, hurdle, box, partner, or implement setup that matches the card.","Rehearse the lower-level pattern first and confirm the athlete can land quietly with trunk and knee-foot alignment.","Give one clear task cue and one stop cue before the set begins."],"execution_steps":["Start tall and organized with eyes up and ribs stacked over pelvis.","Create the required jump, hop, bound, drop, throw, or reactive action with high intent.","Land through the whole foot or appropriate forefoot contact without collapsing, twisting, or reaching excessively.","Stick, rebound, cut, sprint, or reset exactly as the drill requires.","Stop the set when output, timing, landing, spacing, or decision quality is no longer repeatable."],"coach_cues":["Quiet contact.","Push the ground away.","Own the landing before the next answer.","Fast intent, full reset.","Knee tracks over mid-foot."],"athlete_cues":["Quiet contact.","Push the ground away.","Own the landing before the next answer.","Fast intent, full reset.","Knee tracks over mid-foot."],"quality_gate":["Every rep looks fast, quiet, and aligned.","No visible knee collapse, trunk dumping, heel whip, toe drag, or uncontrolled rotation.","The athlete can stop, stick, or redirect on command.","The next rep is not slower or louder than the previous rep."],"common_faults":["Chasing distance or height before earning landing shape.","Adding too many contacts because the exercise looks simple.","Progressing cue complexity before the base contact is clean.","Using the drill late in the session after fatigue has dulled contact quality."],"stop_signs":["Pain, guarding, limping, or change in mechanics.","Loud or flat landings, slow ground contacts, or repeated balance losses.","Fatigue turns the drill into conditioning instead of Output quality.","Unsafe spacing, surface, equipment, or partner communication."]}'::jsonb),
  ('Low Box Drop to Quarter-Squat Rebound', 'low-box-drop-to-quarter-squat-rebound', 'Perform Low Box Drop to Quarter-Squat Rebound as a low-volume, high-quality plyometric or reactive-output exposure. The exercise targets short drop absorption and immediate vertical re-output. The coach should cap volume, demand clean landings, and stop the set before contact quality fades.', 'INTERMEDIATE', 8, 3, 4, NULL, 105, 35, 'individual', 'Low Box Drop to Quarter-Squat Rebound is a level-3 high-impact Output drill for short drop absorption and immediate vertical re-output.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Coach this as level-3 high-impact Output work: small dose, long enough rest, clean projection, quiet landings, and an immediate stop when posture, timing, alignment, or reaction quality changes.', 'Fast and clean. Leave the ground with intent, land quietly, own the finish, and reset before the next rep.', 'High-Impact Level 3-4 Plyometric / Reactive Output', 'output', 'elastic_stiffness_plyometric_rudiments', 'low_box_drop_quarter_squat_rebound', '{"primary_joint_actions":["ankle plantarflexion and dorsiflexion","knee flexion-extension control","hip flexion-extension","trunk bracing"],"primary_tissues":["calf complex","Achilles tendon","quadriceps","patellar tendon","glutes","hip flexors","abdominals","obliques"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_exhale_or_relaxed_reset","balance_demand":"dynamic","coordination_demand":"high","impact_level":3,"surface_needs":"flat, non-slip, shock-absorbing surface with safe spacing","readiness_prerequisites":["Pain-free jumping, hopping, landing, and deceleration patterns.","Can demonstrate a lower-level landing or rebound progression quietly and under control.","Understands stop command and can reset between reps."]}'::jsonb, '{"movement_description":"Perform Low Box Drop to Quarter-Squat Rebound as a low-volume, high-quality plyometric or reactive-output exposure. The exercise targets short drop absorption and immediate vertical re-output. The coach should cap volume, demand clean landings, and stop the set before contact quality fades.","setup":["Choose a safe lane, surface, target, cone, hurdle, box, partner, or implement setup that matches the card.","Rehearse the lower-level pattern first and confirm the athlete can land quietly with trunk and knee-foot alignment.","Give one clear task cue and one stop cue before the set begins."],"execution_steps":["Start tall and organized with eyes up and ribs stacked over pelvis.","Create the required jump, hop, bound, drop, throw, or reactive action with high intent.","Land through the whole foot or appropriate forefoot contact without collapsing, twisting, or reaching excessively.","Stick, rebound, cut, sprint, or reset exactly as the drill requires.","Stop the set when output, timing, landing, spacing, or decision quality is no longer repeatable."],"coach_cues":["Quiet contact.","Push the ground away.","Own the landing before the next answer.","Fast intent, full reset.","Knee tracks over mid-foot."],"athlete_cues":["Quiet contact.","Push the ground away.","Own the landing before the next answer.","Fast intent, full reset.","Knee tracks over mid-foot."],"quality_gate":["Every rep looks fast, quiet, and aligned.","No visible knee collapse, trunk dumping, heel whip, toe drag, or uncontrolled rotation.","The athlete can stop, stick, or redirect on command.","The next rep is not slower or louder than the previous rep."],"common_faults":["Chasing distance or height before earning landing shape.","Adding too many contacts because the exercise looks simple.","Progressing cue complexity before the base contact is clean.","Using the drill late in the session after fatigue has dulled contact quality."],"stop_signs":["Pain, guarding, limping, or change in mechanics.","Loud or flat landings, slow ground contacts, or repeated balance losses.","Fatigue turns the drill into conditioning instead of Output quality.","Unsafe spacing, surface, equipment, or partner communication."]}'::jsonb),
  ('Step-Off to Single-Leg Stick', 'step-off-to-single-leg-stick', 'Perform Step-Off to Single-Leg Stick as a low-volume, high-quality plyometric or reactive-output exposure. The exercise targets unilateral landing accountability from a small step-off. The coach should cap volume, demand clean landings, and stop the set before contact quality fades.', 'INTERMEDIATE', 8, 2, 3, NULL, 75, 35, 'individual', 'Step-Off to Single-Leg Stick is a level-3 high-impact Output drill for unilateral landing accountability from a small step-off.', 'Primary subrole: single_leg_elastic_control. Coach this as level-3 high-impact Output work: small dose, long enough rest, clean projection, quiet landings, and an immediate stop when posture, timing, alignment, or reaction quality changes.', 'Fast and clean. Leave the ground with intent, land quietly, own the finish, and reset before the next rep.', 'High-Impact Level 3-4 Plyometric / Reactive Output', 'output', 'single_leg_elastic_control', 'step_off_single_leg_stick', '{"primary_joint_actions":["ankle plantarflexion and dorsiflexion","knee flexion-extension control","hip flexion-extension","trunk bracing"],"primary_tissues":["intrinsic foot","plantar fascia","calf complex","Achilles tendon","quadriceps","patellar tendon","glutes","hip flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_exhale_or_relaxed_reset","balance_demand":"dynamic","coordination_demand":"high","impact_level":3,"surface_needs":"flat, non-slip, shock-absorbing surface with safe spacing","readiness_prerequisites":["Pain-free jumping, hopping, landing, and deceleration patterns.","Can demonstrate a lower-level landing or rebound progression quietly and under control.","Understands stop command and can reset between reps."]}'::jsonb, '{"movement_description":"Perform Step-Off to Single-Leg Stick as a low-volume, high-quality plyometric or reactive-output exposure. The exercise targets unilateral landing accountability from a small step-off. The coach should cap volume, demand clean landings, and stop the set before contact quality fades.","setup":["Choose a safe lane, surface, target, cone, hurdle, box, partner, or implement setup that matches the card.","Rehearse the lower-level pattern first and confirm the athlete can land quietly with trunk and knee-foot alignment.","Give one clear task cue and one stop cue before the set begins."],"execution_steps":["Start tall and organized with eyes up and ribs stacked over pelvis.","Create the required jump, hop, bound, drop, throw, or reactive action with high intent.","Land through the whole foot or appropriate forefoot contact without collapsing, twisting, or reaching excessively.","Stick, rebound, cut, sprint, or reset exactly as the drill requires.","Stop the set when output, timing, landing, spacing, or decision quality is no longer repeatable."],"coach_cues":["Quiet contact.","Push the ground away.","Own the landing before the next answer.","Fast intent, full reset.","Knee tracks over mid-foot."],"athlete_cues":["Quiet contact.","Push the ground away.","Own the landing before the next answer.","Fast intent, full reset.","Knee tracks over mid-foot."],"quality_gate":["Every rep looks fast, quiet, and aligned.","No visible knee collapse, trunk dumping, heel whip, toe drag, or uncontrolled rotation.","The athlete can stop, stick, or redirect on command.","The next rep is not slower or louder than the previous rep."],"common_faults":["Chasing distance or height before earning landing shape.","Adding too many contacts because the exercise looks simple.","Progressing cue complexity before the base contact is clean.","Using the drill late in the session after fatigue has dulled contact quality."],"stop_signs":["Pain, guarding, limping, or change in mechanics.","Loud or flat landings, slow ground contacts, or repeated balance losses.","Fatigue turns the drill into conditioning instead of Output quality.","Unsafe spacing, surface, equipment, or partn